questions.prompt:
Complete three small tasks. (a) Rewrite the if/else below as a ternary. (b) Write a switch for the deliverySpeed variable. (c) Use the || default value pattern.

```js
// (a) Convert to ternary:
let deliveryLabel;
if (orderTotal >= 50000) {
  deliveryLabel = "Free delivery";
} else {
  deliveryLabel = "₦500 delivery fee";
}

// (b) Write a switch — 'express' → 'Arrives today', 'standard' → 'Arrives in 2 days', 'economy' → 'Arrives in 5 days'
const deliverySpeed = "standard";

// (c) recipientName may be empty — use || to default to 'Valued Customer'
const recipientName = "";
```

questions.expected_answer:
const orderTotal = 60000; // assume this exists

// (a) Ternary
const deliveryLabel = orderTotal >= 50000 ? "Free delivery" : "₦500 delivery fee";
console.log(deliveryLabel); // Free delivery (60000 >= 50000)

// (b) Switch
const deliverySpeed = "standard";
switch (deliverySpeed) {
  case "express":
    console.log("Arrives today");
    break;
  case "standard":
    console.log("Arrives in 2 days");  // runs
    break;
  case "economy":
    console.log("Arrives in 5 days");
    break;
  default:
    console.log("Unknown delivery speed:", deliverySpeed);
}

// (c) || default value
const recipientName  = "";
const displayRecipient = recipientName || "Valued Customer";
console.log("For:", displayRecipient); // For: Valued Customer
